import api from './api';

// Create a booking
export const createBooking = async (bookingData) => {
  const response = await api.post('/bookings', bookingData);
  return response.data;
};

// Get user's bookings (uses the same endpoint with auth filtering)
export const getMyBookings = async () => {
  const response = await api.get('/bookings'); // Fixed: was /bookings/my-bookings
  return response.data;
};

// Cancel booking (uses DELETE, not PUT)
export const cancelBooking = async (id) => {
  const response = await api.delete(`/bookings/${id}`); // Fixed: matches your backend route
  return response.data;
};

export default { createBooking, getMyBookings, cancelBooking };
